// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('approval-history', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('approval-history', async function() {
    // Test name: approval-history
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/user/evaluation/8/approval-history | 
    await driver.get("http://localhost:4200/user/evaluation/8/approval-history");

    // 2 | setWindowSize | 1360x768 | 
    await driver.manage().window().setRect({ width: 1360, height: 768 });

    // 3 | click | id=login_form_email | 
    await driver.findElement(By.id("login_form_email")).click();

    // 4 | type | id=login_form_email | vietnam.system
    await driver.findElement(By.id("login_form_email")).sendKeys("vietnam.system");

    // 5 | click | id=login_form_password | 
    await driver.findElement(By.id("login_form_password")).click();

    // 6 | type | id=login_form_password | 12345678
    await driver.findElement(By.id("login_form_password")).sendKeys("12345678");

    // 7 | click | css=.ant-btn > span | 
    await driver.findElement(By.css(".ant-btn > span")).click();

    // 8 | assertText | xpath=//div[@id='root']/section/section/main/h3 | 承認履歴
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/h3")).getText() == "承認履歴");

    // 9 | assertText | xpath=//div[@id='root']/section/section/main/form/div/div/div/label | 2023下期期評価表
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/form/div/div/div/label")).getText() == "2023下期期評価表");

    // 10 | assertText | xpath=//div[@id='root']/section/section/main/form/div[2]/div/div/label | 評価期間
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/form/div[2]/div/div/label")).getText() == "評価期間");

    // 11 | assertText | xpath=//div[@id='root']/section/section/main/form/div[3]/div/div/label | 氏名
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/form/div[3]/div/div/label")).getText() == "氏名");

    // 12 | assertText | xpath=//div[@id='root']/section/section/main/form/div[4]/div/div/label | 部署
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/form/div[4]/div/div/label")).getText() == "部署");

    // 13 | assertText | xpath=//div[@id='root']/section/section/main/form/div[5]/div/div/label | 等級
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/form/div[5]/div/div/label")).getText() == "等級");

    // 14 | assertText | xpath=//div[@id='root']/section/section/main/form/div[6]/div/div/label | 評価者
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/form/div[6]/div/div/label")).getText() == "評価者");

    // 15 | storeAttribute | xpath=//div[@id='root']/section/section/main/h4@style | target_setting_style
    {
      const attribute = await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/h4")).getAttribute("style");
      vars["target_setting_style"] = attribute;
    }

    // 16 | assert | target_setting_style | margin-bottom: 15px;
    assert(vars["target_setting_style"].toString() == "margin-bottom: 15px;");

    // 17 | click | css=.ant-btn-primary | 
    await driver.findElement(By.css(".ant-btn-primary")).click();

    // 18 | mouseOver | css=.ant-btn-primary | 
    {
      const element = await driver.findElement(By.css(".ant-btn-primary"));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }

    // 19 | mouseOut | css=.ant-btn-sm | 
    {
      const element = await driver.findElement(By.CSS_SELECTOR, "body");
      await driver.actions({ bridge: true }).moveToElement(element, 0, 0).perform();
    }

    // 20 | click | css=.ant-btn-primary:nth-child(2) > span | 
    await driver.findElement(By.css(".ant-btn-primary:nth-child(2) > span")).click();

    // 21 | close |  | 
    await driver.close();
  });
});
